import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {'27': {'1': "<p>In that day YHWH will punish with his fierce, great, powerful sword: Leviathan the fleeing serpent and Leviathan the twisting serpent, and he will slay the dragon (<em>tannin</em>) in the sea. Leviathan is the chaos-monster of ANE mythology, representing cosmic disorder and the powers that oppose YHWH's good creation (Job 41, Ps 74:14, Ps 104:26). The eschatological sword-against-Leviathan is the culmination of the divine warrior's campaign: the creation's enemy is finally slain. In the NT, the dragon of Rev 12-13 is the same figure — the ancient serpent, who is the devil (Rev 12:9) — and his defeat at the return of Christ is the fulfillment of this verse. The sword of the Spirit (Eph 6:17) and the sword of the Rider (Rev 19:15) are the same sword with which YHWH destroys Leviathan.</p>", '2': "<p>In that day, sing about it: a vineyard of choice wine! The vineyard song immediately follows the Leviathan-defeat: when the cosmic enemy is slain, creation's fruitfulness is restored. The vineyard of choice wine inverts the vineyard of wild grapes in 5:1-7 — the same vineyard image, now redeemed. In the NT, Jesus identifies himself as the true vine (John 15:1) and the kingdom of God as the vineyard (Matt 21:33-43); the song of the choice-wine vineyard is the eschatological celebration of the kingdom that the Servant establishes.</p>", '3': '<p>I, YHWH, tend it; I water it constantly; I guard it day and night so nothing can hurt it. YHWH as the tireless gardener contrasts with the vineyard-owner of 5:1-6 who gave up on his vineyard. The constant watering and day-and-night guarding are the images of devoted covenant care. In the NT, Jesus says that his Father is the vinedresser (John 15:1) who tends and prunes the vine and its branches. The divine gardening is the pattern of the resurrection encounter: Mary Magdalene mistakes the risen Jesus for the gardener (John 20:15) — and she is not wrong, for he is the gardener of the new creation.</p>', '4': "<p>I have no wrath against my vineyard. If briers and thorns came against me in battle, I would stride through them and burn them all. The reversal of 5:6 (I will command the clouds not to rain on it) and 9:18 (evil burns like fire, consuming briers and thorns): now YHWH's fire is directed against the vineyard's enemies, not against the vineyard itself. The briers and thorns are the covenant-curse vegetation of Gen 3:18 — the same thorns placed on Jesus' head at the crucifixion (Matt 27:29) as the curse he absorbs, clearing the curse from the vineyard.</p>", '5': "<p>Or else let him come to me for refuge; let him make peace with me — yes, let him make peace with me. The alternative to facing YHWH's consuming fire is taking refuge in YHWH himself: the one who burns the briers is also the refuge for those who come. The making of peace with YHWH is the covenant-negotiation language. In the NT: God was in Christ reconciling the world to himself (2 Cor 5:19); the invitation is to be reconciled to God (2 Cor 5:20). The command to make peace with YHWH is the OT form of the NT gospel call.</p>", '6': '<p>In coming days Jacob will take root; Israel will blossom and sprout and fill the whole world with fruit. The restoration of Israel is described in botanical terms: rooting, blossoming, sprouting, filling. The filling of the whole world with fruit is the Abrahamic promise (Gen 12:3: all families of the earth will be blessed) applied to the restored Israel. In the NT, Paul uses agricultural language for the Gentile mission: if the root is holy, so are the branches (Rom 11:16); the olive tree of Israel into which Gentiles are grafted bears fruit for the whole world. The whole-world-filled-with-fruit is the mission of the church as the extension of restored Israel.</p>', '7': "<p>Has YHWH struck Israel as he struck those who attacked Israel? Has Israel been killed as she killed her enemies? The proportionality question: YHWH's discipline of Israel was measured differently from his destruction of Israel's enemies. The answer is no — the discipline of the covenant community is corrective, not annihilating. This principle is the theological foundation of the NT distinction between judgment for the world and discipline for the church: the Lord disciplines those he loves (Heb 12:6, Prov 3:12). Israel's exile was a father's rod, not an executioner's sword.</p>", '8': "<p>By measured exile he dealt with Israel; he removed her with his fierce wind — the scorching east wind. The exile is <em>measured</em> (<em>besaassea</em>) — controlled, proportional, purposeful. The east wind (sirocco) that withers vegetation is YHWH's instrument of discipline. In the NT, the fire that tests each person's work (1 Cor 3:13) is similarly measured: it tests, refines, and reveals — it does not annihilate those who are in Christ. The measured discipline is the dark side of the love that preserves the covenant community.</p>", '9': "<p>By this, Jacob's guilt will be atoned for; this is the full result of removing his sin: he will crush the altar stones to powder, and Asherah poles and incense altars will no longer stand. The exile itself becomes the atoning mechanism — the suffering of exile purges the idolatry that caused it. The crushed altar-stones are the specific evidence that the idolatry has been broken: the Asherah poles and incense altars of Baal worship will be gone. In the NT, the cross is the supreme atonement (53:10 — his nefesh given as an asham); but the suffering of the church (1 Pet 4:12-13) participates in this purifying work, burning away what is wood, hay, and stubble.</p>", '10': "<p>The fortified city stands deserted; its dwellings abandoned like a wilderness — there calves graze and lie down, stripping its branches. The specific city of judgment (Samaria, or the cities of the exile) is now pasture. The calves browsing in the ruins are the peace-in-desolation image that will be reversed in the new creation's animals lying down together (65:25, 11:6). The ruins of the judged city are the foil for the built-up city of the Branch's kingdom.</p>", '11': '<p>When its branches wither, they are broken off; women come and make fires with them. For this is a people without understanding; therefore its Maker will not have compassion on it, and its Creator will not be gracious to it. The withered-and-broken branches that fuel fire is the image Jesus uses in John 15:6 — the branch that does not remain in the vine withers, is gathered, thrown into the fire, and burned. The lack of understanding is the covenant-failure failure of perception: the people cannot read what YHWH is doing because they have no living connection to the vine.</p>', '12': "<p>In that day YHWH will thresh his grain from the Euphrates to the Brook of Egypt, and you will be gathered up one by one, O sons of Israel. The threshing — separating grain from chaff across the full extent of the diaspora — is the ingathering of the exiles. The one-by-one gathering is the Shepherd's individual care: he knows each sheep by name (John 10:3) and leaves the ninety-nine to find the one (Luke 15:4-7). The eschatological regathering is both universal (from Euphrates to Egypt) and individual (one by one).</p>", '13': '<p>In that day a great trumpet will sound, and those perishing in Assyria and those exiled in Egypt will come and worship YHWH on the holy mountain in Jerusalem. The great trumpet is the signal for the final ingathering — the same trumpet of Rev 11:15 (the seventh trumpet, when the kingdom of the world becomes the kingdom of our Lord and of his Messiah). Paul uses this language in 1 Cor 15:52 (at the last trumpet, the dead will be raised) and Matt 24:31 (the Son of Man will send his angels with a loud trumpet call to gather his elect from the four winds). The great trumpet of Isaiah 27 is the eschatological gathering of the scattered covenant community into the worship of the holy mountain — fulfilled in the new Jerusalem of Rev 21-22 where all nations bring their glory.</p>'}, '28': {'1': "<p>Woe to the proud crown of Ephraim's drunkards — their glorious beauty is a fading flower on the head of the fertile valley of those overcome with wine. The northern kingdom (Ephraim/Israel) is addressed first: its capital Samaria sat on a hill above the fertile valleys, its wealth coming from agriculture, but its leaders are drunk. The proud crown (<em>atarah ge'ut</em>) is both the literal garland worn by drunken revelers and a metaphor for the kingdom's misplaced pride. In the NT, the pride that is a crown of fading flowers is contrasted with the crown of life (Rev 2:10) and the imperishable crown (1 Cor 9:25) that the faithful receive — the kind of glory that does not wither.</p>", '2': "<p>See, the Lord has a powerful agent — like a devastating hailstorm, a destructive tempest, a flood of overwhelming water — he will throw it down to the ground with his hand. The agent of judgment (Assyria historically; any instrument of YHWH's wrath) comes with all the force of natural catastrophe: hail, tempest, flood. The three images are the weapons of the divine warrior. In the NT, the same imagery appears in Rev 16:21 (huge hailstones from heaven) as the final judgment instrument. The one who can deploy hail, tempest, and flood is the same one who calmed the storm at a word (Mark 4:39) — his power over chaos is the power of the Creator exercising sovereignty in both salvation and judgment.</p>", '3': "<p>The proud crown of Ephraim's drunkards will be trampled underfoot. The trampling-underfoot is the final indignity for what was a crown: the symbol of pride becomes mud. In the NT, the church is the body of the one before whom every knee will bow (Phil 2:10) — the reversal: not pride trampled, but humility exalted. The crown that Ephraim made of pride is contrasted with the crown of thorns pressed on Jesus (Matt 27:29) — human pride expressed as a mock-crown becomes the actual mark of the King who absorbs the judgment that pride deserves.</p>", '4': "<p>The beautiful crown on the fertile valley will be like a first-ripe fig before summer — whoever sees it swallows it as soon as he has it in his hand. The first-ripe fig is the most desirable fruit — it disappears instantly when found. Samaria's wealth and beauty are consumed immediately by the conquering power that seizes it. Jesus curses the fig tree (Matt 21:19-20) for having no fruit — the inverse of the first-ripe-fig eagerness; the covenant community with the appearance of fruitfulness but no actual fruit is more condemned than the Ephraim that at least attracted legitimate desire.</p>", '5': "<p>In that day YHWH of hosts will be a glorious crown and a beautiful diadem for the remnant of his people. The crown of the remnant is YHWH himself — the reverse of the false crown of Ephraim (v 1). YHWH as crown-of-his-people is the ultimate honor: the people do not make YHWH their ornament; YHWH makes himself their glory. In the NT, the church's boast is in Christ (1 Cor 1:31; Jer 9:24): the crown that does not fade (1 Pet 5:4) is the crown of the Chief Shepherd himself.</p>", '6': '<p>He will be a spirit of justice for those who sit in judgment, and strength for those who repel battle at the gate. YHWH provides both judicial wisdom (for judges) and military strength (for defenders) — the two functions of covenant governance. In the NT, the Spirit given at Pentecost is the same spirit of justice: the Paraclete who convicts the world concerning sin, righteousness, and judgment (John 16:8). The strength for defenders at the gate is the spiritual armor of Eph 6:10-18, provided by the same YHWH who stands at the gate of history.</p>', '7': "<p>But priest and prophet stagger from strong drink; they are confused by wine; they err in vision, they stumble in judgment. The covenant community's leaders — specifically the spiritual leaders, priest and prophet — are the ones who have given themselves to drunkenness. The erring in vision and stumbling in judgment is the consequence: the very functions that qualify them for office (vision for the prophet, judgment for the priest) are destroyed by the very sin they should warn against. In the NT, the requirement of sobriety for elders and overseers (1 Tim 3:2-3, Titus 1:7-8) is the positive construction of what this verse describes negatively.</p>", '8': "<p>All the tables are covered with vomit and filth; there is no clean space anywhere. The graphic physical description is not gratuitous — it is the prophetic literalization of the metaphorical condition: the tables where covenantal meals should be celebrated (the feast of 25:6!) are defiled by the physical consequence of the leaders' spiritual condition. The tables of the covenant community, which should be set with YHWH's provision (23:5: a table before me in the presence of my enemies), have become what the leaders have made of them.</p>", '9': "<p>Who is he trying to teach? Who is he trying to make understand his message? Babies just weaned from milk, infants just taken from the breast? The scoffers mock the prophet's message as elementary — fit only for infants. The contempt is aimed at the prophet's simple, repetitive instruction (v 10). In the NT, Paul subverts this contempt: the wisdom of the cross is foolishness to the world (1 Cor 1:18-25), and spiritual things are spiritually discerned — the mature can receive solid food, but those who scoff at elementary things are themselves infants (1 Cor 3:1-3, Heb 5:11-14).</p>", '10': "<p>For it is rule on rule, rule on rule; line on line, line on line; a little here, a little there. The mocking imitation of the prophet's repetitive teaching style — the children's rhyme quality (<em>tsav latsav tsav latsav</em> in Hebrew, onomatopoeic and demeaning). The scoffers experience YHWH's instruction as infantilizing and tedious. In the NT, the same dynamic: the gospel's simplicity (the proclamation of Christ crucified, 1 Cor 2:2) is dismissed by the sophisticated as beneath consideration — yet it is the power of God to salvation (Rom 1:16).</p>", '11': "<p>For by people of strange lips and a foreign tongue YHWH will speak to this people. Because the covenant people rejected YHWH's instruction through the prophet's familiar voice, YHWH will speak to them through the alien voice of the conquering Assyrian army — an incomprehensible tongue that makes his message unmistakable by its very unintelligibility. Paul quotes this verse in 1 Cor 14:21-22 in his discussion of tongues: tongues are a sign not for believers but for unbelievers — the strange-lips pattern of judgment. The Pentecost phenomenon (Acts 2:4-12) is the redemptive inversion: the strange tongues are now a sign of blessing rather than judgment, understandable to those who receive the Spirit.</p>", '12': "<p>He said to them: This is the place of rest; give rest to the weary; this is the refreshing. But they refused to listen. The rest and refreshing that YHWH offered through the prophet's simple instruction is the same rest Jesus offers: come to me, all who are weary and burdened, and I will give you rest (Matt 11:28-30, citing this verse). The Israel that refused to listen to the prophetic invitation to sabbath-rest is the same Israel that Jesus weeps over — so often I wanted to gather your children, but you were unwilling (Matt 23:37). The refusal of rest-in-YHWH is the fundamental covenant failure that judgment reverses.</p>", '13': "<p>So the word of YHWH will become to them: rule on rule, rule on rule; a little here, a little there — so that when they walk they will stumble backward and be injured, snared and taken captive. The instruction they mocked as infantile becomes the very mechanism of their stumbling: hearing YHWH's word but not understanding it results in walking into judgment blindly. The stumbling-backward image anticipates 8:14-15 (he will be a stone of stumbling and a rock of offense) and its NT application: the stone the builders rejected has become the cornerstone — but it causes those who reject it to stumble (Rom 9:32-33, 1 Pet 2:8).</p>", '14': "<p>So hear the word of YHWH, you scoffers who rule this people in Jerusalem. The oracle pivots south to Jerusalem, where the same contempt for YHWH's word governs the city. The scoffers who rule (<em>anshei latson</em> — men of scoffing) are the leadership class of Jerusalem. Their specific sin is political pragmatism in the face of Assyrian threat — making diplomatic arrangements that bypass YHWH. In the NT, the same category of scoffer appears as those who deny the coming of the Lord (2 Pet 3:3-4): the eschatological scoffers are the covenant pattern applied to the last age.</p>", '15': '<p>You have said: We have made a covenant with death; with Sheol we have an agreement. When the overwhelming flood sweeps through, it will not reach us, for we have made lies our refuge and falsehood our hiding place. The covenant with death is the political alliance with Egypt or Assyria — YHWH uses this striking metaphor to expose what the alliance really is: a deal with the anti-life powers of the underworld. The lies and falsehood (<em>shav</em> and <em>sheqer</em>) are the treaty guarantees that cannot be trusted. In the NT: those who trust in the powers of death and Sheol cannot escape them; only the one who holds the keys of death and Hades (Rev 1:18) can nullify the covenant with death.</p>', '16': '<p>So this is what the Lord GOD says: See, I am laying a stone in Zion — a tested stone, a precious cornerstone, a sure foundation. Whoever trusts in it will not be put to shame. The cornerstone oracle is one of the most NT-cited verses in Isaiah. Paul quotes it in Rom 9:33 (combined with 8:14) and 1 Cor 3:11; Peter quotes it in 1 Pet 2:6; Jesus cites Ps 118:22 which is the companion text. The tested stone, precious cornerstone, sure foundation is the Messiah himself: he is the foundation that cannot be shaken (1 Cor 3:11 — no one can lay a foundation other than the one already laid, which is Jesus Christ). Whoever trusts in it will not be put to shame: faith in the Cornerstone is the only alternative to the covenant with death (v 15). The not-put-to-shame is quoted in Rom 10:11 as the universal promise of gospel faith.</p>', '17': "<p>I will measure with justice as my plumb line and righteousness as my level. The hail will sweep away your refuge of lies, and water will overwhelm your hiding place. YHWH's architectural measurement uses his own character — justice and righteousness — as the standards. What is built on the cornerstone of v 16 will be measured by these standards and found true; what was built on lies (v 15) will be swept away. The hail and overwhelming water are the judgment instruments of v 2 now directed specifically at the false refuge. In the NT, the house built on the rock vs. the house built on sand (Matt 7:24-27) is the same measurement: the storm reveals what the foundation was.</p>", '18': '<p>Your covenant with death will be cancelled, and your agreement with Sheol will not hold. When the overwhelming flood sweeps through, you will be beaten down by it. The nullification of the covenant with death: what they thought was their insurance policy proves worthless when judgment arrives. The overwhelming flood cannot be stopped by diplomatic agreements. In the NT, the covenant with death is cancelled not by the judgment coming upon the scoffers but by the resurrection of the Servant: death is swallowed up in victory (1 Cor 15:54-57, citing Isa 25:8). The covenant with death is annulled not because it never existed but because the one who holds the keys of death has broken its power.</p>', '19': '<p>Every time it sweeps through, it will seize you — morning after morning, by day and by night. The very understanding of the message will bring only terror. The relentless coming of judgment — morning and night, again and again — gives no rest. The terror-understanding is the terrible irony: finally understanding what YHWH has been saying (rule on rule, line on line) only means understanding the judgment that follows rejection. In the NT: those who have heard and rejected cannot escape what follows (Heb 10:26-27 — if we deliberately keep on sinning after receiving knowledge of the truth, no sacrifice for sins is left).</p>', '20': "<p>The bed is too short to stretch out on, and the covering too narrow to wrap yourself in. The proverb of inadequate coverage: the false security of the political alliance is like a bed that doesn't fit, covers that don't reach. No human arrangement is adequate to cover the full extent of the need. In the Christological reading: the only covering that is truly adequate is the robe of righteousness (61:10) and the garment of salvation — the coverage provided by the Servant's atonement that covers sin completely (53:6: YHWH laid on him the iniquity of us all).</p>", '21': "<p>For YHWH will rise up as he did at Mount Perazim (2 Sam 5:20) and as in the valley of Gibeon (Josh 10:12-14) — to carry out his task, his strange task, and to do his work, his alien work. YHWH's judgment on his own people is his strange work (<em>zar maasse</em>) and alien work (<em>nokri pe'ulato</em>) — what he does with his enemies (destroying nations) he now does with his covenant community. The strangeness signals that judgment of the covenant community is not YHWH's preference but his necessity: the love that disciplines is a different expression of the same fidelity. In the NT: judgment begins with the household of God (1 Pet 4:17) — the same strange-work logic applied to the church age.</p>", '22': "<p>Now stop your mocking, or your bonds will grow tighter. I have heard from YHWH a decree of complete destruction for the whole land. The final warning: the scoffing makes the bonds tighter — the attitude of contempt for YHWH's word compounds the guilt. The decree of complete destruction (<em>kalah venechcretset</em>) is the most severe prophetic word — it echoes 10:23 and anticipates the 70 CE judgment on Jerusalem. In the NT: every careless word spoken will be judged (Matt 12:36); the hardening of the heart under divine warning produces increasingly irreversible consequences.</p>", '23': "<p>Listen and hear my voice; pay attention and hear what I say. The prophetic call to hearing, in the form of the wisdom tradition's summons to a parable (the farmer, vv 24-28). The hearing-call after the judgment oracle invites the community to find wisdom in the agricultural parable that follows. In the NT, Jesus similarly uses agricultural parables to invite hearing: whoever has ears to hear, let him hear (Matt 13:9). The parable is the form of revelation that both conceals (from those who mock) and reveals (to those who listen).</p>", '24': "<p>Does a farmer spend the whole day plowing in order to plant? Does he keep breaking up the clods of his field forever? The agricultural wisdom: plowing has a purpose (breaking up the ground) and a limit (it must be followed by planting). The farmer knows when each phase ends. The parable's logic is that YHWH's judgments — the plowing and threshing — are purposive and limited, not eternal or gratuitous. In the NT, the parable of the soils (Matt 13:3-9) is the wisdom extension of this agricultural theology: the soil is prepared so that seed can be sown and bear fruit.</p>", '25': "<p>When he has leveled the surface, he broadcasts caraway, scatters cumin, plants wheat in rows, barley in its proper place, and emmer in its border. The variety of seeds sown in the proper manner for each — the farmer's wisdom is in knowing which seed goes where and how. YHWH's wisdom in dealing with his people is similarly differentiated: different judgments and mercies are applied in the right measure at the right time. The diversity of seeds is the diversity of the covenant community — each receiving what is appropriate for growth.</p>", '26': "<p>His God instructs him in the right way and teaches him. The farmer's agricultural wisdom comes from God: it is not merely practical knowledge but divinely taught skill. This grounds the parable's theology: YHWH is the one who teaches both the farmer and the prophet, both agriculture and covenant relationship. In the NT, the Spirit is the divine teacher who guides into all truth (John 16:13) — the same divine instruction applied to the new covenant community.</p>", '27': "<p>Caraway is not threshed with a sledge, nor does a cartwheel roll over cumin — caraway is beaten with a stick, and cumin with a rod. The wisdom of proportional threshing: small seeds require gentle treatment. The heavy sledge and cartwheel appropriate for grain would crush the delicate caraway. YHWH's judgment is similarly calibrated: the measure of discipline is appropriate to what is being refined. The NT equivalent: God is faithful and will not let you be tempted beyond what you can bear (1 Cor 10:13) — the divine calibration of testing to the capacity of the one being tested.</p>", '28': "<p>Grain for bread must be crushed, but a farmer does not go on threshing it forever. He drives his cartwheel over it, but his horses do not crush it. The limit of threshing: grain must be processed, but not destroyed. The crushing is purposive (to produce flour for bread) and has an end-point. The bread that results from the crushed grain is the NT's broken bread: this is my body, broken for you (1 Cor 11:24). The Servant who is crushed (53:5 — he was crushed because of our iniquities) is the grain-for-bread that YHWH threshes with purpose — not for destruction but for the bread of life.</p>", '29': "<p>All of this too comes from YHWH of hosts, whose counsel (<em>eitsah</em>) is wonderful and whose skill (<em>tushiyah</em>) is great. The parable closes with a doxology of divine wisdom: the agricultural wisdom that gives the parable its form, the prophetic wisdom that judges and redeems, and the eschatological wisdom that governs all of history — all come from the same source. The wonderful-counsel of YHWH is the same wonderful-counselor attribute of the Davidic child-king (9:6) — the Messiah who embodies YHWH's wisdom is the fulfillment of the agricultural wisdom the farmer received from God.</p>"}, '29': {'1': "<p>Woe to Ariel — the mysterious title for Jerusalem (Ariel means either lion of God or altar hearth). Add year to year; let the festivals continue their cycle. The festivals continuing is bitter irony: Jerusalem keeps its religious calendar while continuing in the spiritual condition that makes the feasts hollow. Jesus makes the same charge: you travel land and sea to make a single proselyte (Matt 23:15), while maintaining the outward forms of devotion. The religious cycle without repentance is the covenant community's deepest self-deception.</p>", '2': "<p>Yet I will besiege Ariel; there will be mourning and lamentation, and she will become to me like an altar hearth. The altar-hearth (Ariel) becomes the city of destruction — a grim wordplay. The city built around the altar of sacrifice becomes itself an altar on which offerings are consumed. In the NT, the temple's destruction in 70 CE is the fulfillment: the place of sacrifice is itself sacrificed. Jesus weeps that Jerusalem did not know the time of her visitation (Luke 19:44) — the city that could not recognize YHWH's arrival becomes the city of mourning.</p>", '3': "<p>I will encamp against you on every side; I will besiege you with a mound and raise siege-works against you. The siege of Jerusalem by YHWH himself — using enemy armies as his instrument — is the supreme covenant-judgment: the divine protector becomes the divine besieger. The NT application: the siege of Jerusalem by Rome in 66-70 CE is described by Jesus as the days of vengeance to fulfill all that is written (Luke 21:22). The judgment-from-outside on the covenant community is YHWH's judgment executed through human agents.</p>", '4': '<p>Then you will be brought low; you will speak from the ground, and your words will come up from the dust; your voice will be like one from the dead, chirping from the ground. The low-speaking from the ground and dust is the posture of the defeated city: Jerusalem, which spoke from the heights of Zion (2:3: from Zion the law will go out), now speaks from the grave. The voice from the dust is the mourning whisper of the vanquished. Yet in the Christological pattern, it is the Servant who descends to the dust of death (Ps 22:15) and speaks from the lowest place — and is vindicated and raised from that same dust.</p>', '5': "<p>But the horde of your enemies will become like fine dust, and the multitude of the ruthless like blowing chaff. And in a sudden moment, YHWH will intervene. The sudden reversal: the besieging army that was about to consume Jerusalem will itself be consumed like chaff. The sudden-moment pattern (cf. 37:36 — the angel of YHWH put to death 185,000 Assyrians overnight) is the pattern of divine intervention that changes everything instantly. In the NT, the Son of Man coming on the clouds (Matt 24:30) is the ultimate sudden intervention — the parousia as the decisive reversal of all that opposes YHWH's people.</p>", '6': "<p>You will be visited by YHWH of hosts with thunder and earthquake and great noise, with storm and tempest and flame of devouring fire. The theophanic arsenal — thunder, earthquake, noise, storm, tempest, fire — is the same weapons-of-the-divine-warrior imagery as chapter 13. YHWH's visitation is always attended by these forces: they are the peripheral phenomena of his presence. The NT: at the transfiguration, a voice came from a bright cloud (Matt 17:5); at the cross, the earth shook and rocks split (Matt 27:51); at the end, the same cosmic phenomena attend the return of the Son of Man.</p>", '7': "<p>And the multitude of all the nations that fight against Ariel — all who fight against her and her fortifications — will be like a dream, like a vision in the night. The nations besieging Jerusalem will dissolve like a dream: what seemed overwhelmingly real (the siege, the threat) will prove insubstantial when YHWH acts. The dream-dissolution is the anti-Nebuchadnezzar image: his vision of the statue dissolved before the stone from heaven (Dan 2:34-35, 44-45). In the NT, the same dissolution of the enemies of YHWH's city: the new Jerusalem has no need for defense because its enemies have melted away before the glory of the Lamb (Rev 21:24-27).</p>", '8': "<p>As when a hungry man dreams of eating and wakes still hungry, or when a thirsty man dreams of drinking and wakes still craving — so the nations that fight against Zion will be when they wake. The hunger-and-thirst that cannot be satisfied by dreaming is the condition of those who oppose YHWH's purposes: they strain toward what they cannot attain. In the NT, the hunger and thirst that is satisfied is the hunger and thirst for righteousness (Matt 5:6: they will be filled) — the opposite of the frustrated dream-hunger of YHWH's enemies. The bread of life and living water that Jesus gives are the satisfaction that ends all dream-hunger.</p>", '9': "<p>Be stunned and bewildered; be blinded and stay blind! They are drunk, but not with wine; they stagger, but not with strong drink. The spiritual stupor of Jerusalem's people who have seen the signs and understood nothing. The drunk-but-not-with-wine is the same diagnostic as 28:1, 7 — spiritual confusion that mimics physical intoxication. The not-from-wine specification is crucial: no natural substance causes this condition; only the withdrawal of divine understanding can produce it. Paul applies this logic in Rom 11:7-8 (quoting Isa 29:10 and Deut 29:4): Israel has not obtained what it was seeking, but the elect obtained it — the rest were hardened.</p>", '10': "<p>For YHWH has poured out on you a spirit of deep sleep; he has shut your eyes — the prophets — and covered your heads — the seers. The divine role in the hardening: YHWH pours out the spirit of deep sleep on those whose repeated rejection of his word has brought them to the point of irreversibility. The closing of the prophets' eyes and seers' heads is the covenant community's judgment: the mediators of revelation are themselves shut down, leaving the community without guidance. Paul quotes this verse (Rom 11:8) in his discussion of Israel's hardening — the eyes closed so that they cannot see is the judgment side of the Servant's mission to open eyes (42:7).</p>", '11': '<p>And the vision of all this has become like the words of a sealed book. When someone gives it to a literate person, saying Read this, he answers I cannot, for it is sealed. The sealed book of prophetic vision makes reading impossible even for the literate: having the physical text is not the same as having access to its meaning. In the NT: the scroll of Revelation (Rev 5:1-5) is sealed with seven seals and no one in heaven or on earth can open it — until the Lamb who was slain takes it and opens it. The sealed book of Isaiah 29 finds its final form in the sealed scroll that only the Lion of Judah/Lamb can open.</p>', '12': "<p>And when the book is given to one who cannot read, saying Please read this, he answers I cannot read. The illiterate person also cannot access the sealed vision — neither literacy nor illiteracy can open what YHWH has sealed. The double impossibility (literate and illiterate both fail) establishes that no human capacity can unlock divine revelation. In the NT: flesh and blood did not reveal this to you, but my Father in heaven (Matt 16:17); the natural person does not accept the things of the Spirit of God (1 Cor 2:14). The Spirit's revelation is the only key to the sealed book.</p>", '13': "<p>And the Lord said: Because this people draw near with their mouth and honor me with their lips, while their heart is far from me, and their fear of me is a commandment of men learned by rote. The lips-heart gap is the prophetic diagnosis of religious formalism: elaborate verbal devotion that originates from human tradition rather than from genuine encounter with YHWH. Jesus quotes this verse directly in Matt 15:8-9 (and Mark 7:6-7) as his critique of the Pharisees' hand-washing tradition: in vain they worship me, teaching as doctrines the precepts of men. The application to the NT community is direct and intentional: this is the diagnostic that distinguishes living faith from religious performance throughout the canon.</p>", '14': "<p>Therefore, watch — I am about to do something astonishing among this people, something astonishing and astounding; the wisdom of the wise will perish, and the discernment of the discerning will be hidden. YHWH's response to the lips-heart religion is not refinement of the existing system but the radical new act that confounds all human wisdom. Paul quotes this verse in 1 Cor 1:19 (I will destroy the wisdom of the wise; the intelligence of the intelligent I will frustrate) as the description of what God did in the cross: the crucifixion of Christ is the wisdom-destroying astonishing-thing that makes all human religious calculation irrelevant. The cross is the fulfillment of this verse: the greatest wisdom-confounding event in history.</p>", '15': '<p>Woe to those who go to great lengths to hide their plans from YHWH, who work in darkness and say Who sees us? Who knows us? The theological assumption behind hiding from YHWH is that he is limited in sight and knowledge — the same error as Adam hiding in the garden (Gen 3:8-9). In the NT: there is nothing hidden that will not be disclosed (Luke 8:17, 12:2-3); God will bring to light what is hidden in darkness and expose the motives of the heart (1 Cor 4:5). The YHWH who sees in secret (Matt 6:4, 6, 18) is the one from whom nothing can be hidden.</p>', '16': "<p>How you have everything backwards! Should the potter be regarded as no different from the clay? Should what is made say of its maker He did not make me? Should the pot say of the potter He has no understanding? The potter-clay inversion is the fundamental ontological error: the creature claiming equality with or independence from the Creator. Paul uses this verse extensively in Rom 9:20-21 in his discussion of divine sovereignty in election: does not the potter have the right to make from the same lump of clay some pottery for special purposes and some for common use? The NT application is not about fatalism but about the creature's inability to overrule the Creator's purposes — including the purpose of the Servant's atoning work.</p>", '17': "<p>Is it not just a little while until Lebanon becomes a fruitful orchard, and the fruitful orchard is considered a forest? The reversal of nature — wilderness to orchard, orchard to forest — is YHWH's sovereign ability to transform the landscape of his purposes. The little-while urgency marks the imminent reversal that the following verses describe (vv 18-19): the deaf will hear, the blind will see, the meek will find joy. The transformation of Lebanon into orchard is the de-wildernessing of what was untamed — the same creational transformation of 32:15-16 and 35:1-7.</p>", '18': "<p>In that day the deaf will hear the words of a book, and out of gloom and darkness the eyes of the blind will see. The reversal of the sealed-book blindness of vv 11-12 and the spirit-of-deep-sleep of v 10: those who could not read the sealed book will hear it; those whose eyes were closed will see. Jesus applies these specific reversals to his own ministry: go tell John what you hear and see — the blind receive sight, the deaf hear (Matt 11:4-5, citing Isa 35:5-6 and 29:18). The opening of deaf ears and blind eyes is the Servant's commission (42:7: to open eyes that are blind and free captives from prison) and the sign that the Messianic age has arrived.</p>", '19': "<p>The meek will find renewed joy in YHWH, and the poorest among people will exult in the Holy One of Israel. The meek (<em>anawim</em>) and the poor (<em>evyonim</em>) — the same community as the afflicted of 61:1 — are the specific recipients of the eschatological reversal. They find joy in YHWH, not merely in improved circumstances: the source of the joy is YHWH's character (Holy One of Israel) not YHWH's gifts alone. The meek who inherit the earth (Matt 5:5) and the poor in spirit who inherit the kingdom (Matt 5:3) are the NT form of these same anawim-evyonim who exult in the Holy One.</p>", '20': '<p>For the tyrant will be no more, and the scoffer will vanish, and all who look for opportunity to do wrong will be cut off. The three classes eliminated: tyrant, scoffer (the mockiers of 28:14), and those who trap the innocent (v 21). The removal of these three produces the social conditions for the meek and poor to flourish (v 19). In the NT, the casting out of the devil (John 12:31: the ruler of this world will be driven out) and the final judgment on the beast and false prophet (Rev 19:20) are the eschatological fulfillment: the tyrant and scoffer of cosmic scope are finally removed.</p>', '21': '<p>Those who trap a man with a word, who lay snares for the one who rebukes corruption at the gate, and who use empty claims to turn away justice. The snare-setters who trap with words: the specific form of oppression in the judicial setting (the gate). The ones who rebuke corruption at the gate — the prophets and honest judges — are the ones being snared. In the NT, the Pharisees repeatedly try to trap Jesus with words (Matt 22:15-18: they tried to catch him in his words; Matt 22:35: one of them, an expert in the law, tested him with a question). The one who rebuffs every word-snare is the wise Servant who does not open his mouth (53:7) — he refuses the trap by silence.</p>', '22': "<p>Therefore thus says YHWH, who redeemed Abraham, concerning the house of Jacob: Jacob will no longer be ashamed; his face will no longer grow pale. The redemption of Abraham — the founding act of the covenant — is the ground of Jacob's coming vindication. YHWH who called one person from the far country (51:2) will not abandon the descendants of that one person to permanent shame. The not-be-ashamed promise is the same as the cornerstone promise of 28:16 (whoever trusts in it will not be put to shame): the foundation of the shame-removal is the Messiah who bears the shame (53:3: despised and rejected) so that the community carries it no longer.</p>", '23': "<p>For when he sees his children — the work of my hands — in his midst, they will sanctify my name; they will sanctify the Holy One of Jacob and stand in awe of the God of Israel. The children as the work of YHWH's hands: the restored covenant community is YHWH's creation, not Israel's achievement. Their sanctifying of YHWH's name is the doxological response to what they see YHWH has done. The Holy One of Jacob — the unique Isaianic title that unites the covenant-particularity (Jacob) with the absolute holiness — is the object of the eschatological awe. This is the sanctifying of YHWH's name that the Lord's Prayer anticipates: hallowed be your name (Matt 6:9).</p>", '24': "<p>Those who went astray in spirit will come to understanding, and those who complained will accept instruction. The final reversal: the wayward and the grumbling will be turned to understanding and teachability. This is the work of the new heart (36:26, Jer 31:33-34) — not improvement of the old heart but the divine gift of a new capacity for instruction. In the NT, the Spirit's role in illumination (1 Cor 2:12-13: we have received the Spirit who is from God so that we may understand what God has freely given us) is the fulfillment: those who went astray in spirit receive the Spirit who leads into all truth (John 16:13).</p>"}}

def main():
    data = load_comm('mkt-christ', 'isaiah')
    merge_comm(data, ISAIAH)
    chs = sorted(data.keys(), key=lambda x: int(x))
    total_v = sum(len(data[c]) for c in chs)
    print(f'Isaiah christ: {len(chs)} chapters, {total_v} verses')
    save_comm('mkt-christ', 'isaiah', data)

if __name__ == '__main__':
    main()
